                "edits": [
                    "not a dict",
                    {"old_string": "a", "new_string": "b"},
                ],
            },
        )
        self.assertEqual(len(result["edits"]), 2)
        self.assertIn("error", result["edits"][0])
        self.assertEqual(
            result["edits"][1], {"old_string": "a", "new_string": "b"}
        )


