/**
 * True when the installed relic's on-disk content differs from the shipped
 * SOURCE. Uses the same deterministic hash as signing (hashRelicContent), so a
 * re-signature alone â€” which only rewrites the signature-bearing manifest fields
 * that the hash strips â€” does NOT register as drift. A missing or unreadable
 * installed directory counts as drift (it must be repaired).
 */
async function relicContentDrifted(sourcePath: string, installedDir: string): Promise<boolean> {
  const sourceHash = await hashRelicContent(sourcePath);
  let installedHash: string;
  try {
    installedHash = await hashRelicContent(installedDir);
  } catch {
    return true;
  }
  return sourceHash !== installedHash;
}

/**
 * Resolves the shipped SOURCE directory for an installed relic id, or null when
 * none ships with the app (a third-party relic with nothing to refresh from).
 * Mirrors the MarketplaceInstaller bundled:// order: seed-relics, then
 * bundled-relics.
 */
async function resolveRelicSource(relicId: string): Promise<string | null> {
  const candidates = [
    path.join(resolveSeedRelicsDir(), relicId),
    path.join(resolveBundledRelicsDir(), relicId),
  ];
  for (const candidate of candidates) {
    try {
      const stat = await fs.stat(path.join(candidate, "relic.json"));
      if (stat.isFile()) return candidate;
    } catch {
      // Not present under this source root â€” try the next.
    }
  }
  return null;
}

/**
 * Repairs already-installed relics whose shipped source content has drifted from
 * the installed copy â€” e.g. a first-party seed relic shipped a content change (a
 * CSS token rename) WITHOUT a version bump, leaving the installed copy stale and
 * failing activation on every launch (the midnight-forge --qs-* case).
 *
 * Runs AFTER installBundledRelics so a genuine version upgrade has already
 * re-copied fresh content and reports no drift. Refresh-only: it never installs
 * a relic the user has not already installed (preserving marketplace opt-in) and
 * skips relics that ship no bundled source. One relic's failure never blocks the
 * others.
 */
export async function refreshDriftedRelics(
  homeDir: string,
  relicService: RelicService
): Promise<void> {
  const registry = await loadRegistry(homeDir);

  for (const entry of registry) {
    const relicId = entry.manifest.id;
    try {
      const sourcePath = await resolveRelicSource(relicId);
      if (!sourcePath) continue; // third-party relic â€” nothing to refresh from

      const installedDir = getRelicDirectory(homeDir, relicId);
      if (!(await relicContentDrifted(sourcePath, installedDir))) continue; // in sync

      // Validate the source BEFORE removing the installed copy, so a bad source
      // can never leave the user with no relic.
      const rawManifest = await readSourceManifest(sourcePath);
      const validation = validateManifest(rawManifest);
      if (!validation.valid) {
        console.warn(
          LOG_PREFIX,
          `Skipping drift refresh of '${relicId}': invalid source manifest:`,
          validation.errors
        );
        continue;
      }

      const wasActive = entry.state === "active" || entry.state === "error";
      const wasBundled = entry.bundled === true;
      console.log(LOG_PREFIX, `Refreshing drifted relic '${relicId}' from shipped source`);

      await relicService.uninstall(relicId);
      await relicService.install(sourcePath);
      if (wasActive) {
        await relicService.activate(relicId);
      }

      // install() does not carry the bundled flag; restore it so a refreshed
      // bundled relic is not silently reclassified as user-installed.
      if (wasBundled) {
        const refreshed = await loadRegistry(homeDir);
        const refreshedEntry = refreshed.find((r) => r.manifest.id === relicId);
        if (refreshedEntry && refreshedEntry.bundled !== true) {
          refreshedEntry.bundled = true;
          await saveRegistry(homeDir, refreshed);
        }
      }
    } catch (error) {
      console.error(LOG_PREFIX, `Failed to refresh drifted relic '${relicId}':`, error);
    }
  }
}

