import "server-only";

/**
 * The one HMAC signing key for short server-issued tokens (sessions, visitor
 * ids). Real key in prod; a fixed dev key only when no key is configured
 * (local/CI/e2e). Fails closed in production: signing with the public dev key
 * would let anyone forge a token, so we refuse rather than degrade (mirrors
 * stateKey() in google/oauth.ts).
 */
export function signingKey(): string {
  const k = process.env.HUZZAH_ENCRYPTION_KEY;
  if (k) return k;
  if (process.env.NODE_ENV === "production") {
    throw new Error("HUZZAH_ENCRYPTION_KEY is required to sign tokens in production.");
  }
  return "huzzah-dev-insecure-session-key";
}

