import "server-only";
import { createHmac, randomUUID, timingSafeEqual } from "node:crypto";
import { signingKey } from "@/lib/signing-key";

/**
 * Visitor identity for public smoke-test pages. The id is minted and HMAC-signed
 * on the server and carried in an httpOnly cookie, so a client can no longer
 * supply arbitrary visitor keys in the request body and farm verified
 * page_visit events. Forging a new identity now requires a fresh cookie jar,
 * and the public endpoints are IP rate limited on top.
 */
export function mintVisitorToken(): { id: string; token: string } {
  const id = randomUUID();
  return { id, token: `${id}.${sign(id)}` };
}

/** Returns the visitor id when the token verifies, or null for anything else. */
export function verifyVisitorToken(token: string | null | undefined): string | null {
  if (!token) return null;
  const dot = token.lastIndexOf(".");
  if (dot <= 0 || dot === token.length - 1) return null;
  const id = token.slice(0, dot);
  const sig = Buffer.from(token.slice(dot + 1));
  const expected = Buffer.from(sign(id));
  if (sig.length !== expected.length || !timingSafeEqual(sig, expected)) return null;
  return id;
}

function sign(id: string): string {
  return createHmac("sha256", signingKey()).update(`vid:${id}`).digest("base64url");
}

