import "server-only";

/**
 * Fixed-window, in-memory rate limiter for the public endpoints (visit beacon,
 * signup). Per-instance by design: v0 runs a single Railway instance. If the
 * app ever scales out, move the window state to a shared store.
 */
const windows = new Map<string, { count: number; resetAt: number }>();
const MAX_KEYS = 10_000;

/** True when the caller is within the limit for this window; false = throttled. */
export function rateLimit(key: string, limit: number, windowMs: number): boolean {
  const t = Date.now();
  const w = windows.get(key);
  if (!w || w.resetAt <= t) {
    if (windows.size >= MAX_KEYS) prune(t);
    windows.set(key, { count: 1, resetAt: t + windowMs });
    return true;
  }
  w.count += 1;
  return w.count <= limit;
}

function prune(t: number): void {
  for (const [k, w] of windows) {
    if (w.resetAt <= t) windows.delete(k);
  }
  // Adversarial key churn (spoofed IPs) could fill the map with live windows;
  // dropping all state costs at most one window of extra requests.
  if (windows.size >= MAX_KEYS) windows.clear();
}

/** Best-effort client IP for rate-limit keys (first x-forwarded-for hop). */
export function clientIpFrom(headers: { get(name: string): string | null }): string {
  const fwd = headers.get("x-forwarded-for");
  if (fwd) {
    const first = fwd.split(",")[0]?.trim();
    if (first) return first;
  }
  return "unknown";
}

