import { NextResponse, type NextRequest } from "next/server";
import { appUrl } from "@/lib/config";
import { clientIpFrom, rateLimit } from "@/lib/rate-limit";
import { recordPageVisit } from "@/lib/services/pages";
import { mintVisitorToken, verifyVisitorToken } from "@/lib/visitor-token";

const VID_COOKIE = "huzzah_vid";
const VID_TTL_S = 60 * 60 * 24 * 365;

/**
 * Visit beacon. Called by a client effect on the public page, so only real
 * browsers executing JS hit it (bots, unfurlers, and router prefetch do not).
 *
 * Visitor identity is a server-minted, HMAC-signed httpOnly cookie; the request
 * body is never trusted. A client used to be able to POST arbitrary visitor
 * keys and farm verified page_visit events; now farming requires a fresh cookie
 * jar per hit AND slipping under the per-IP rate limit.
 */
export async function POST(req: NextRequest, ctx: { params: Promise<{ slug: string }> }) {
  const { slug } = await ctx.params;
  if (!rateLimit(`visit:${clientIpFrom(req.headers)}`, 30, 60_000)) {
    return NextResponse.json({ ok: false }, { status: 429 });
  }

  const existingId = verifyVisitorToken(req.cookies.get(VID_COOKIE)?.value);
  const minted = existingId ? null : mintVisitorToken();
  const visitorId = existingId ?? minted!.id;

  await recordPageVisit(slug, visitorId);

  const res = NextResponse.json({ ok: true });
  if (minted) {
    res.cookies.set(VID_COOKIE, minted.token, {
      httpOnly: true,
      sameSite: "lax",
      secure: appUrl().startsWith("https"),
      path: "/",
      maxAge: VID_TTL_S,
    });
  }
  return res;
}

