"use client";

import { useEffect } from "react";

/**
 * Fires a single visit beacon per browser session. Runs only in a real browser
 * (a useEffect), so non-JS bots, link unfurlers, and router prefetch never count
 * as visits. Visitor identity is a server-signed httpOnly cookie minted by the
 * visit endpoint; the client sends nothing it could forge. The sessionStorage
 * flag only saves redundant posts within a tab session.
 */
export function VisitBeacon({ slug }: { slug: string }) {
  useEffect(() => {
    try {
      const sessionFlag = `huzzah_visited_${slug}`;
      if (sessionStorage.getItem(sessionFlag)) return;
      sessionStorage.setItem(sessionFlag, "1");
      void fetch(`/api/p/${encodeURIComponent(slug)}/visit`, {
        method: "POST",
        keepalive: true,
      });
    } catch {
      // storage blocked / private mode -> skip silently
    }
  }, [slug]);

  return null;
}

