/** Daily-loop Move: approve and "send" the drafted outreach. */
export async function approveAndSendOutreachAction(
  moveId: string,
  recipients?: Record<string, string>,
): Promise<{ sent: number; win: Win | null }> {
  const companyId = await requireCompany();
  const store = await getStore();
  const move = await store.getMove(moveId);
  if (!move || move.companyId !== companyId) throw new Error("Move not found.");

  // Only the drafts the AI prepared for THIS move's mission are sent. The
  // approval is strictly scoped to what the founder reviewed.
  const drafts = (await store.listOutreach(companyId)).filter(
    (o) => o.status === "drafted" && o.missionId === move.missionId,
  );

  const { mode, mailer, founder } = await getGoogleForCompany(companyId);
  const fromEmail = founder.googleEmail ?? founder.email;

  let firstEventId: string | null = null;
  let lastWin: Win | null = null;
  for (const d of drafts) {
    if (d.gmailMessageId) continue; // already sent; never re-send

    // The founder may supply/correct the recipient email at approval time.
    const recipient = recipients?.[d.id]?.trim().toLowerCase();
    if (recipient && recipient.includes("@")) {
      await store.updateProspect(d.prospectId, { contact: recipient });
    }
    const prospect = await store.getProspect(d.prospectId);

    let verifiedBy: VerificationSource = "human_attested";
    let ref = d.id;
    let gmailIds: { gmailMessageId?: string; gmailThreadId?: string } = {};

    if (mode === "real" && prospect?.contact) {
      try {
        const r = await mailer.sendEmail({
          to: prospect.contact,
          toName: prospect.name,
          fromEmail,
          fromName: founder.name,
          subject: d.subject,
          body: d.body,
          threadId: d.gmailThreadId,
        });
        verifiedBy = "gmail_api";
        ref = r.messageId;
        gmailIds = { gmailMessageId: r.messageId, gmailThreadId: r.threadId };
      } catch (e) {
        if (e instanceof GoogleAuthRevokedError || e instanceof GoogleScopeError) {
          await store.updateFounder(founder.id, { googleTokenEnc: null });
          throw new Error("Your Google connection needs to be reconnected before sending.");
        }
        // Transient or missing-recipient: fall back to attested for THIS draft only.
      }
    }

    const res = await recordOutcome({
      companyId,
      type: "email_sent",
      verifiedBy,
      ref,
      payload: { prospectId: d.prospectId, mode },
    });
    if (!firstEventId) firstEventId = res.event.id;
    if (res.win) lastWin = res.win;
    await store.updateOutreach(d.id, { status: "sent", sentAt: now(), ...gmailIds });
    await store.updateProspect(d.prospectId, { status: "contacted" });
  }

  if (firstEventId) {
    await store.updateMove(moveId, { status: "done", completedViaEventId: firstEventId });
  }
  revalidatePath("/today");
  return { sent: drafts.length, win: lastWin };
}

