export async function submitSignupAction(
  slug: string,
  email: string,
  honeypot?: string,
): Promise<{ ok: boolean }> {
  // Bots fill hidden fields. Pretend success so they do not retry.
  if (honeypot && honeypot.trim().length > 0) return { ok: true };
  // Public endpoint: throttle per IP so a script cannot hose the signup path.
  if (!rateLimit(`signup:${clientIpFrom(await headers())}`, 10, 60_000)) {
    return { ok: false };
  }
  const normalized = (email ?? "").trim().toLowerCase();
  if (!isValidEmail(normalized)) return { ok: false };
  const { ok } = await recordSignup(slug, normalized);
  return { ok };
}

