// @vitest-environment node
import { describe, it, expect } from "vitest";
import { isSampleTranscript, SAMPLE_CALL } from "./coach-sample";

describe("isSampleTranscript", () => {
  it("matches the sample exactly", () => {
    expect(isSampleTranscript(SAMPLE_CALL)).toBe(true);
  });

  it("matches the sample regardless of whitespace shape", () => {
    expect(isSampleTranscript(`  ${SAMPLE_CALL}  `)).toBe(true);
    expect(isSampleTranscript(SAMPLE_CALL.replace(/\n/g, "  \n\n "))).toBe(true);
    expect(isSampleTranscript(SAMPLE_CALL.replace(/ /g, "\t"))).toBe(true);
  });

  it("does not match a real transcript of similar length", () => {
    const real = SAMPLE_CALL.replace("small gyms", "dog groomers");
    expect(isSampleTranscript(real)).toBe(false);
  });

  it("does not match empty or short input", () => {
    expect(isSampleTranscript("")).toBe(false);
    expect(isSampleTranscript("Me: hi\nThem: hello")).toBe(false);
  });
});

