// @vitest-environment node
import { describe, it, expect } from "vitest";
import { mintVisitorToken, verifyVisitorToken } from "./visitor-token";

describe("visitor tokens", () => {
  it("round-trips: a minted token verifies to its id", () => {
    const { id, token } = mintVisitorToken();
    expect(verifyVisitorToken(token)).toBe(id);
  });

  it("mints distinct ids", () => {
    expect(mintVisitorToken().id).not.toBe(mintVisitorToken().id);
  });

  it("rejects null, undefined, and empty", () => {
    expect(verifyVisitorToken(null)).toBeNull();
    expect(verifyVisitorToken(undefined)).toBeNull();
    expect(verifyVisitorToken("")).toBeNull();
  });

  it("rejects tokens without a separator or with an empty part", () => {
    expect(verifyVisitorToken("no-separator")).toBeNull();
    expect(verifyVisitorToken(".sigonly")).toBeNull();
    expect(verifyVisitorToken("idonly.")).toBeNull();
  });

  it("rejects a tampered id (client cannot choose its own key)", () => {
    const { token } = mintVisitorToken();
    const dot = token.lastIndexOf(".");
    const forged = `attacker-chosen-id${token.slice(dot)}`;
    expect(verifyVisitorToken(forged)).toBeNull();
  });

  it("rejects a tampered signature", () => {
    const { token } = mintVisitorToken();
    const flipped = token.slice(0, -1) + (token.endsWith("A") ? "B" : "A");
    expect(verifyVisitorToken(flipped)).toBeNull();
  });

  it("rejects a signature of the wrong length", () => {
    const { token } = mintVisitorToken();
    expect(verifyVisitorToken(`${token}AA`)).toBeNull();
  });
});

