// @vitest-environment node
import { describe, it, expect, vi, afterEach } from "vitest";
import { clientIpFrom, rateLimit } from "./rate-limit";

afterEach(() => {
  vi.useRealTimers();
});

describe("rateLimit", () => {
  it("allows up to the limit and throttles past it", () => {
    const key = `t:${Math.random()}`;
    for (let i = 0; i < 5; i++) expect(rateLimit(key, 5, 60_000)).toBe(true);
    expect(rateLimit(key, 5, 60_000)).toBe(false);
    expect(rateLimit(key, 5, 60_000)).toBe(false);
  });

  it("resets after the window expires", () => {
    vi.useFakeTimers();
    const key = `t:${Math.random()}`;
    for (let i = 0; i < 3; i++) rateLimit(key, 3, 1_000);
    expect(rateLimit(key, 3, 1_000)).toBe(false);
    vi.advanceTimersByTime(1_001);
    expect(rateLimit(key, 3, 1_000)).toBe(true);
  });

  it("tracks keys independently", () => {
    const a = `a:${Math.random()}`;
    const b = `b:${Math.random()}`;
    expect(rateLimit(a, 1, 60_000)).toBe(true);
    expect(rateLimit(a, 1, 60_000)).toBe(false);
    expect(rateLimit(b, 1, 60_000)).toBe(true);
  });
});

describe("clientIpFrom", () => {
  it("takes the first x-forwarded-for hop", () => {
    const h = new Headers({ "x-forwarded-for": "203.0.113.9, 10.0.0.1" });
    expect(clientIpFrom(h)).toBe("203.0.113.9");
  });

  it("falls back to unknown when absent or malformed", () => {
    expect(clientIpFrom(new Headers())).toBe("unknown");
    expect(clientIpFrom(new Headers({ "x-forwarded-for": " , " }))).toBe("unknown");
  });
});

