// @vitest-environment node
/**
 * Guards for the "nothing counts unless it really happened" rule at the action
 * layer. The chokepoint (outcome-ledger) has its own guard tests; these assert
 * the actions can no longer feed it fiction:
 *  - the built-in practice sample can never mint an interview_completed event
 *  - approve-and-send records email_sent ONLY for emails that verifiably left
 *    (no recipient -> skipped, Gmail failure -> failed; neither records)
 *  - the public signup action throttles per IP
 */
import { describe, it, expect, vi, beforeEach, type Mock } from "vitest";

const { sessionMock, storeMock, ledgerMock, googleMock, coachMock, headersMock } = vi.hoisted(
  () => ({
    sessionMock: { getSessionFounderId: vi.fn() },
    storeMock: {
      getCompanyByFounderId: vi.fn(),
      getCurrentIdea: vi.fn(),
      listProspects: vi.fn(),
      addProspect: vi.fn(),
      updateProspect: vi.fn(),
      addInterview: vi.fn(),
      addInsight: vi.fn(),
      getMove: vi.fn(),
      listOutreach: vi.fn(),
      getProspect: vi.fn(),
      updateOutreach: vi.fn(),
      updateMove: vi.fn(),
      updateFounder: vi.fn(),
    },
    ledgerMock: {
      recordOutcome: vi.fn(),
      completeMoveWithOutcome: vi.fn(),
    },
    googleMock: { getGoogleForCompany: vi.fn() },
    coachMock: { scoreInterview: vi.fn() },
    headersMock: { headers: vi.fn() },
  }),
);

vi.mock("next/cache", () => ({ revalidatePath: vi.fn() }));
vi.mock("next/headers", () => ({ headers: headersMock.headers }));
vi.mock("@/lib/session", () => ({
  getSessionFounderId: sessionMock.getSessionFounderId,
  clearSession: vi.fn(),
}));
vi.mock("@/lib/store", () => ({ getStore: vi.fn(async () => storeMock) }));
vi.mock("@/lib/services/outcome-ledger", () => ({
  recordOutcome: ledgerMock.recordOutcome,
  completeMoveWithOutcome: ledgerMock.completeMoveWithOutcome,
}));
vi.mock("@/lib/services/coach", () => ({ scoreInterview: coachMock.scoreInterview }));
vi.mock("@/lib/services/journey", () => ({ advanceStageIfReady: vi.fn(async () => 2) }));
vi.mock("@/lib/llm", () => ({ getLlmForCompany: vi.fn(async () => ({})) }));
vi.mock("@/lib/integrations/google", () => {
  class GoogleAuthRevokedError extends Error {}
  class GoogleScopeError extends Error {}
  return {
    getGoogleForCompany: googleMock.getGoogleForCompany,
    GoogleAuthRevokedError,
    GoogleScopeError,
  };
});
vi.mock("@/lib/services/pages", () => ({
  recordSignup: vi.fn(async () => ({ ok: true, win: null })),
  deploySmokeTestPage: vi.fn(),
}));

import { SAMPLE_CALL } from "@/lib/coach-sample";
import {
  approveAndSendOutreachAction,
  logInterviewAction,
  scoreSampleCallAction,
  submitSignupAction,
} from "./actions";
import { recordSignup } from "@/lib/services/pages";

const SCORE = {
  demandVerdict: "warm" as const,
  talkedTooMuch: false,
  askedForCommitment: true,
  leadingQuestions: 0,
  quotes: [{ text: "we lost 15 slots last month", tag: "real_signal" as const }],
  summary: "Clean call.",
};

beforeEach(() => {
  vi.clearAllMocks();
  sessionMock.getSessionFounderId.mockResolvedValue("f1");
  storeMock.getCompanyByFounderId.mockResolvedValue({ id: "c1", founderId: "f1" });
  storeMock.getCurrentIdea.mockResolvedValue({
    problemStatement: "gyms lose money to no-shows",
    targetUser: "gym owners",
  });
  coachMock.scoreInterview.mockResolvedValue(SCORE);
  ledgerMock.recordOutcome.mockResolvedValue({ event: { id: "e1" }, win: null });
  ledgerMock.completeMoveWithOutcome.mockResolvedValue({
    result: { event: { id: "e1" }, win: null },
  });
});

describe("the practice sample can never become progress", () => {
  it("logInterviewAction refuses the sample transcript and records nothing", async () => {
    await expect(logInterviewAction({ transcript: SAMPLE_CALL })).rejects.toThrow(/practice sample/);
    expect(ledgerMock.recordOutcome).not.toHaveBeenCalled();
    expect(ledgerMock.completeMoveWithOutcome).not.toHaveBeenCalled();
    expect(storeMock.addInterview).not.toHaveBeenCalled();
  });

  it("logInterviewAction refuses a whitespace-reshaped sample too", async () => {
    const reshaped = `  ${SAMPLE_CALL.replace(/\n/g, "\n\n")}  `;
    await expect(logInterviewAction({ transcript: reshaped })).rejects.toThrow(/practice sample/);
    expect(ledgerMock.recordOutcome).not.toHaveBeenCalled();
  });

  it("a real transcript of similar length still records", async () => {
    storeMock.listProspects.mockResolvedValue([]);
    storeMock.addProspect.mockResolvedValue({ id: "p1" });
    storeMock.addInterview.mockResolvedValue({ id: "i1" });
    const real = SAMPLE_CALL.replace("small gyms", "dog groomers");
    const res = await logInterviewAction({ transcript: real });
    expect(res.score).toEqual(SCORE);
    expect(storeMock.addInterview).toHaveBeenCalledOnce();
    expect(ledgerMock.recordOutcome).toHaveBeenCalledWith(
      expect.objectContaining({ type: "interview_completed", ref: "i1" }),
    );
  });

  it("scoreSampleCallAction scores but touches nothing", async () => {
    const res = await scoreSampleCallAction();
    expect(res.score).toEqual(SCORE);
    expect(ledgerMock.recordOutcome).not.toHaveBeenCalled();
    expect(ledgerMock.completeMoveWithOutcome).not.toHaveBeenCalled();
    expect(storeMock.addInterview).not.toHaveBeenCalled();
    expect(storeMock.addInsight).not.toHaveBeenCalled();
  });
});

describe("approve-and-send records only what verifiably left", () => {
  const move = { id: "m1", companyId: "c1", missionId: "ms1" };
  const draft = {
    id: "d1",
    prospectId: "p1",
    missionId: "ms1",
    status: "drafted",
    subject: "quick question",
    body: "hello",
    gmailMessageId: null,
    gmailThreadId: null,
  };
  const founder = { id: "f1", name: "Dana", email: "dana@x.test", googleEmail: "dana@x.test" };

  beforeEach(() => {
    storeMock.getMove.mockResolvedValue(move);
    storeMock.listOutreach.mockResolvedValue([draft]);
  });

  it("real mode + no recipient email: skips, records NOTHING", async () => {
    storeMock.getProspect.mockResolvedValue({ id: "p1", name: "Sam", contact: null });
    googleMock.getGoogleForCompany.mockResolvedValue({
      mode: "real",
      mailer: { sendEmail: vi.fn() },
      founder,
    });
    const res = await approveAndSendOutreachAction("m1");
    expect(res).toMatchObject({ sent: 0, skipped: 1, failed: 0 });
    expect(ledgerMock.recordOutcome).not.toHaveBeenCalled();
    expect(storeMock.updateOutreach).not.toHaveBeenCalled();
    expect(storeMock.updateMove).not.toHaveBeenCalled();
  });

  it("real mode + Gmail failure: draft stays drafted, records NOTHING", async () => {
    storeMock.getProspect.mockResolvedValue({ id: "p1", name: "Sam", contact: "sam@x.test" });
    googleMock.getGoogleForCompany.mockResolvedValue({
      mode: "real",
      mailer: { sendEmail: vi.fn().mockRejectedValue(new Error("gmail 500")) },
      founder,
    });
    const res = await approveAndSendOutreachAction("m1");
    expect(res).toMatchObject({ sent: 0, skipped: 0, failed: 1 });
    expect(ledgerMock.recordOutcome).not.toHaveBeenCalled();
    expect(storeMock.updateOutreach).not.toHaveBeenCalled();
    expect(storeMock.updateMove).not.toHaveBeenCalled();
  });

  it("real mode + successful send: records email_sent verified by gmail_api", async () => {
    storeMock.getProspect.mockResolvedValue({ id: "p1", name: "Sam", contact: "sam@x.test" });
    googleMock.getGoogleForCompany.mockResolvedValue({
      mode: "real",
      mailer: {
        sendEmail: vi.fn().mockResolvedValue({ messageId: "gm1", threadId: "th1" }),
      },
      founder,
    });
    const res = await approveAndSendOutreachAction("m1");
    expect(res).toMatchObject({ sent: 1, skipped: 0, failed: 0 });
    expect(ledgerMock.recordOutcome).toHaveBeenCalledExactlyOnceWith(
      expect.objectContaining({ type: "email_sent", verifiedBy: "gmail_api", ref: "gm1" }),
    );
    expect(storeMock.updateOutreach).toHaveBeenCalledWith(
      "d1",
      expect.objectContaining({ status: "sent", gmailMessageId: "gm1" }),
    );
    expect(storeMock.updateMove).toHaveBeenCalledWith(
      "m1",
      expect.objectContaining({ status: "done", completedViaEventId: "e1" }),
    );
  });

  it("no Gmail: the click is an explicit attestation (human_attested)", async () => {
    storeMock.getProspect.mockResolvedValue({ id: "p1", name: "Sam", contact: null });
    googleMock.getGoogleForCompany.mockResolvedValue({
      mode: "mock",
      mailer: { sendEmail: vi.fn() },
      founder,
    });
    const res = await approveAndSendOutreachAction("m1");
    expect(res).toMatchObject({ sent: 1, skipped: 0, failed: 0 });
    expect(ledgerMock.recordOutcome).toHaveBeenCalledExactlyOnceWith(
      expect.objectContaining({ type: "email_sent", verifiedBy: "human_attested" }),
    );
  });
});

describe("public signup is throttled per IP", () => {
  it("allows up to the limit, then refuses", async () => {
    const ip = `198.51.100.${Math.floor(Math.random() * 200)}`;
    headersMock.headers.mockResolvedValue(new Headers({ "x-forwarded-for": ip }));
    for (let i = 0; i < 10; i++) {
      const r = await submitSignupAction("slug", `person${i}@x.test`);
      expect(r.ok).toBe(true);
    }
    const throttled = await submitSignupAction("slug", "person11@x.test");
    expect(throttled.ok).toBe(false);
    expect(recordSignup as Mock).toHaveBeenCalledTimes(10);
  });
});

