export interface BuilderAdapter {
  /**
   * Set by demo adapters whose "source" is an immutable canned fixture. When
   * true, the Launch Safety Check uses the adapter's own findings/remediate
   * paths and NEVER runs the real LLM auditors: a fixture cannot be edited, so
   * a real audit of it produces blockers that can never clear (the exact bug
   * that bricked Stage 4 in production). Real adapters leave this unset, which
   * fails safe: their source is always really audited when a key is present.
   */
  readonly cannedFixture?: boolean;
  /** Instantiate the golden template filled to the spec. */
  createProject(input: CreateProjectInput): Promise<CreateProjectResult>;

